mapper.select:
SELECT *
FROM sous_chef_hp.hp_intake_record
WHERE user_id = #{userId}
  AND date = #{date}
ORDER BY created_time DESC

SELECT *
FROM sous_chef_hp.hp_intake_record
WHERE user_id = #{userId}
  AND date = #{date}
  AND source_type = #{sourceType}
ORDER BY created_time DESC

SELECT *
FROM sous_chef_hp.hp_intake_record
WHERE user_id = #{userId}
  AND date >= #{startDate}
  AND date <= #{endDate}
ORDER BY date DESC, created_time DESC

SELECT
    COALESCE(SUM(effective_energy), 0) as consumedEnergy,
    COALESCE(SUM(effective_fat), 0) as consumedFat,
    COALESCE(SUM(effective_carbohydrates), 0) as consumedCarbohydrates,
    COALESCE(SUM(effective_protein), 0) as consumedProtein
FROM sous_chef_hp.hp_intake_record
WHERE user_id = #{userId}
  AND date >= #{startDate}
  AND date <= #{endDate}
